20:function getCliParams(): { cliCallback: string; state: string } | null {
21:	const params = new URLSearchParams(window.location.search);
22:	const cliCallback = params.get("cli_callback");
23:	const state = params.get("state");
24:	if (!cliCallback || !state) return null;
25:	try {
26:		const url = new URL(cliCallback);
27:		if (url.hostname !== "127.0.0.1") return null;
28:	} catch {
29:		return null;
30:	}
31:	return { cliCallback, state };
32:}
